 1	import React, { Dispatch, FC, SetStateAction } from 'react';
 2	
 3	import { Action, useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
 4	import { DropdownItem } from '@patternfly/react-core';
 5	
 6	import './action-dropdown-item.scss';
 7	
 8	type ActionDropdownItemProps = {
 9	  action: Action;
10	  setIsOpen: Dispatch<SetStateAction<boolean>>;
11	};
12	
13	const ActionDropdownItem: FC<ActionDropdownItemProps> = ({ action, setIsOpen }) => {
14	  const [actionAllowed] = useAccessReview(action?.accessReview);
15	
16	  const handleClick = () => {
17	    if (typeof action?.cta === 'function') {
18	      action?.cta();
19	      setIsOpen(false);
20	    }
21	  };
22	
23	  return (
24	    <DropdownItem
25	      data-test-id={`${action?.id}`}
26	      description={action?.description}
27	      isDisabled={action?.disabled || !actionAllowed}
28	      key={action?.id}
29	      onClick={handleClick}
30	    >
31	      {action?.label}
32	      {action?.icon && <span className="text-muted">{action.icon}</span>}
33	    </DropdownItem>
34	  );
35	};
36	
37	export default ActionDropdownItem;

